    [Fact]    public async Task Test_RequestIdHeaderIsPreserved()
    {
        // When the client supplies X-Request-ID the same value should appear on the response.
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/request_id_header_is_preserved/request-id/preserved");
        request.Headers.Add("X-Request-ID", "trace-123");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        Assert.True(response.Headers.TryGetValues("x-request-id", out var hdrx_request_id) && hdrx_request_id.Any(v => v.Contains("trace-123")), "header x-request-id mismatch");
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"echo\":\"trace-123\",\"status\":\"preserved\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }

    [Fact]    public async Task Test_RequestIdIsGeneratedWhenNotProvided()
    {
        // Ensures the request ID middleware attaches a UUID to responses when the client does not send one.
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/request_id_is_generated_when_not_provided/request-id/generated");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        Assert.True(response.Headers.TryGetValues("x-request-id", out var _uuidHdr) && System.Text.RegularExpressions.Regex.IsMatch(string.Join(", ", _uuidHdr), @"^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$"), "header x-request-id is not a UUID");
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"status\":\"generated\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }

